SELECT o.order_id, p.payment_id, p.payment_method, p.amount, p.payment_status, p.payment_date, p.payment_time
FROM orders o
JOIN payments p ON o.order_id = p.order_id;

SELECT SUM(amount) AS total_amount_paid
FROM payments
WHERE payment_method = 'credit card';

SELECT AVG(sales) AS Average_Sales
FROM orders
WHERE rating >= 4;

SELECT region, COUNT(customer_id) AS Total_Customers, AVG(age) AS Average_Age
FROM customers
GROUP BY region;

SELECT AVG(age) 
FROM customers 
WHERE customer_id IN (SELECT DISTINCT customer_id FROM orders);

SELECT age_group, COUNT(customer_id) AS voyager_count
FROM customer_demographics
GROUP BY age_group;
